{"npsn":"40101987","name":"SMP NEGERI 1 TATAPAAN","address":"Rap-rap","village":"Rap-Rap","status":"Negeri","jenjang":"SMP","district":"Tatapan","regencyBpsCode":"7105","regencyName":"Kabupaten Minahasa Selatan","provinceName":"Sulawesi Utara","school_id":"b19d9bf3-9995-4c96-9542-7fc3dec72b99","user_id":"c538ae9c-f4ed-40d4-8a8a-d10c3b17322c"},
